from flask import Flask, request, jsonify
import redis
import os

app = Flask(__name__)

redis_client = redis.Redis(
    host=os.getenv("REDIS_HOST", "localhost"),
    port=int(os.getenv("REDIS_PORT", "6379")),
    db=int(os.getenv("REDIS_DB", "0")),
    password=os.getenv("REDIS_PASSWORD"),
    decode_responses=True,
)

ALLOWED_COMMANDS = {
    "GET": {"args": 1},
    "MGET": {"min_args": 1},
    "SET": {"min_args": 2},
    "DEL": {"min_args": 1},
    "EXISTS": {"min_args": 1},
    "EXPIRE": {"args": 2},
    "TTL": {"args": 1},
    "PTTL": {"args": 1},
    "INCR": {"args": 1},
    "DECR": {"args": 1},
    "HGET": {"args": 2},
    "HSET": {"min_args": 3},
    "HDEL": {"min_args": 2},
    "HGETALL": {"args": 1},
    "LLEN": {"args": 1},
    "LRANGE": {"args": 3},
    "LPUSH": {"min_args": 2},
    "RPUSH": {"min_args": 2},
    "SADD": {"min_args": 2},
    "SREM": {"min_args": 2},
    "SMEMBERS": {"args": 1},
    "ZADD": {"min_args": 3},
    "ZREM": {"min_args": 2},
    "ZRANGE": {"min_args": 3},
    "PING": {"args": 0},
}

def parse_command(raw_command):
    if not raw_command or not raw_command.strip():
        raise ValueError("Missing command")
    parts = raw_command.strip().split()
    command = parts[0].upper()
    args = parts[1:]
    if command not in ALLOWED_COMMANDS:
        raise ValueError("Command not allowed")
    rules = ALLOWED_COMMANDS[command]
    if "args" in rules and len(args) != rules["args"]:
        raise ValueError(f"{command} expects exactly {rules['args']} argument(s)")
    if "min_args" in rules and len(args) < rules["min_args"]:
        raise ValueError(f"{command} expects at least {rules['min_args']} argument(s)")
    return command, args

def serialize_result(result):
    if isinstance(result, bytes):
        return result.decode("utf-8", errors="replace")
    if isinstance(result, set):
        return sorted(list(result))
    if isinstance(result, (list, tuple)):
        return [serialize_result(item) for item in result]
    if isinstance(result, dict):
        return {serialize_result(k): serialize_result(v) for k, v in result.items()}
    return result

@app.route("/admin/redis", methods=["POST", "GET"])
def execute_redis_command():
    raw_command = request.args.get("command", "")
    try:
        command, args = parse_command(raw_command)
        result = redis_client.execute_command(command, *args)
        return jsonify({
            "ok": True,
            "command": command,
            "args": args,
            "result": serialize_result(result),
        })
    except ValueError as e:
        return jsonify({"ok": False, "error": str(e)}), 400
    except redis.RedisError as e:
        return jsonify({"ok": False, "error": str(e)}), 502

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))